// MsgServer is the server API for Msg service.
type MsgServer interface {
	BeginEpoch(context.Context, *MsgBeginEpoch) (*MsgBeginEpochResponse, error)
	DkgCommit(context.Context, *MsgDkgCommit) (*MsgDkgCommitResponse, error)
	DkgComplaintMissing(context.Context, *MsgDkgComplaintMissing) (*MsgDkgComplaintMissingResponse, error)
	DkgComplaintInvalid(context.Context, *MsgDkgComplaintInvalid) (*MsgDkgComplaintInvalidResponse, error)
	// DkgComplaintAEADBad lets a recipient surface a malformed scalar_ct from
	// a dealer's MsgDkgEncryptedShare. The complainer reveals dh = skR*U plus a
	// Chaum-Pedersen DLEQ proof binding dh to the on-chain (pkR, U); the chain
	// then runs AES-GCM open and compares the recovered scalar to the share
	// point implied by ElGamal V - dh. Slashes the dealer on AEAD-fail or
	// scalar/point mismatch; slashes the complainer on spurious complaint.
	DkgComplaintAEADBad(context.Context, *MsgDkgComplaintAEADBad) (*MsgDkgComplaintAEADBadResponse, error)
	// DkgShareReveal is the LEGACY v1 plaintext reveal path. It remains
	// accepted for backward compatibility with v1 chains; DKG v2 replaces it
	// with MsgDkgEncryptedShare (see docs/DKG-V2.md).
	DkgShareReveal(context.Context, *MsgDkgShareReveal) (*MsgDkgShareRevealResponse, error)
	// DKG v2: encrypted-share delivery. Replaces the plaintext DkgShareReveal
	// once v2 is activated. The message carries an ElGamal ciphertext on the
	// share point plus a 160-byte NIZK binding it to the dealer's Feldman
	// commitments, plus an AES-GCM ciphertext of the share scalar bound to
	// the NIZK via AAD.
	DkgEncryptedShare(context.Context, *MsgDkgEncryptedShare) (*MsgDkgEncryptedShareResponse, error)
	FinalizeEpoch(context.Context, *MsgFinalizeEpoch) (*MsgFinalizeEpochResponse, error)
	DkgTimeout(context.Context, *MsgDkgTimeout) (*MsgDkgTimeoutResponse, error)
	// Randomness-beacon commit-reveal (replaces devnet RandEpoch on prod chains).
	OpenBeaconWindow(context.Context, *MsgOpenBeaconWindow) (*MsgOpenBeaconWindowResponse, error)
	BeaconCommit(context.Context, *MsgBeaconCommit) (*MsgBeaconCommitResponse, error)
	BeaconReveal(context.Context, *MsgBeaconReveal) (*MsgBeaconRevealResponse, error)
	InitHand(context.Context, *MsgInitHand) (*MsgInitHandResponse, error)
	SubmitShuffle(context.Context, *MsgSubmitShuffle) (*MsgSubmitShuffleResponse, error)
	FinalizeDeck(context.Context, *MsgFinalizeDeck) (*MsgFinalizeDeckResponse, error)
	SubmitPubShare(context.Context, *MsgSubmitPubShare) (*MsgSubmitPubShareResponse, error)
	SubmitEncShare(context.Context, *MsgSubmitEncShare) (*MsgSubmitEncShareResponse, error)
	FinalizeReveal(context.Context, *MsgFinalizeReveal) (*MsgFinalizeRevealResponse, error)
	Timeout(context.Context, *MsgTimeout) (*MsgTimeoutResponse, error)
}

